    # PLOT WITH ANNUAL GRAPH LINE OF PASSENGERS
    @render_plotly
    def render_flights_years():
        last_3_years = (END_DATE_SSB-relativedelta(years=3)).replace(month=1, day=1)
        last_year = (END_DATE_SSB -relativedelta(years=1)).replace(month=12, day=31)
        df_plot = (
        df_ssb.filter((pl.col("date").cast(pl.Date).is_between(
                    last_3_years,
                    last_year
                )) & 
                (pl.col("iata_code") == airport()))
        .with_columns([
            pl.col("date").dt.year().alias("year"),
            pl.col("date").dt.month().alias("month"),
        ])
        .group_by(["year", "month"])
        .agg(
            pl.col("flights").sum().alias("flights_total")
        )
        .sort(["year", "month"])
        )
        month_map = {i: calendar.month_abbr[i].lower() for i in range(1, 13)}
        df_plot = df_plot.with_columns(
            pl.col("month").replace_strict(month_map).alias("month_name")
        )

        df_pd = df_plot.to_pandas()

        fig = px.line(
            df_pd,
            x="month_name",
            y="flights_total",
            color="year",  
            markers=True,
            category_orders={
                "month_name": ["jan","feb","mar","apr","may","jun",
                            "jul","aug","sep","oct","nov","dec"],
                "year": [2024, 2025, 2026]
            },
            title="Total monthly flights by year"
        )

        fig.update_layout(
            autosize=True,
            xaxis_title="Month",
            yaxis_title="Flights",
            legend_title="Year",
            paper_bgcolor="white",
            template="plotly_white"
        )

        return fig

    # ========================================================================

    @render_plotly
    def plot_domestic_internatinal():



        # AGGREGATION

        df_plot = (
            ssb_for_last_year()
            .group_by(["year", "month", "international_domestic"])
            .agg(
                pl.col("flights").sum().alias("flights_total")
            )
            .sort(["year", "month"])
        )


        #  MONTH LABELS

        month_map = {i: calendar.month_abbr[i].lower() for i in range(1, 13)}

        df_plot = df_plot.with_columns(
            pl.col("month").replace_strict(month_map).alias("month_name")
        )



        df_pd = df_plot.to_pandas()

        #  PLOTLY

        fig = px.area(
            df_pd,
            x="month_name",
            y="flights_total",
            color="international_domestic",
            facet_col="year",
            markers=True,
            category_orders={
                "month_name": [
                    "jan","feb","mar","apr","may","jun",
                    "jul","aug","sep","oct","nov","dec"
                ]
            },
            title="Domestic vs International Flights by Month and Year"
        )

        fig.update_layout(
            autosize=True,
            xaxis_title="Month",
            yaxis_title="Flights",
            legend_title="Type",
            paper_bgcolor="white",
            template="plotly_white"
        )

        return fig

    # ========================================================================

    @render_plotly
    def plot_arival_departure_growth():


        df = (
            ssb_for_last_year()
            .with_columns([
                pl.col("date").dt.year().alias("year"),
                pl.col("date").dt.month().alias("month"),
            ])
            .group_by(["year", "month", "arrival_departure"])
            .agg(
                pl.col("passengers").sum().alias("passengers_total")
            )
            .pivot(
                values="passengers_total",
                index=["year", "month"],
                columns="arrival_departure"
            )
            .fill_null(0)
            .with_columns(
                (pl.col("A") - pl.col("D")).alias("diff")
            )
            .sort(["year", "month"])
        )


        month_map = {i: calendar.month_abbr[i].lower() for i in range(1, 13)}

        df = df.with_columns(
            pl.col("month").replace_strict(month_map).alias("month_name")
        )

        df_pd = df.to_pandas()

        fig = px.line(
            df_pd,
            x="month_name",
            y="diff",
            color="year",
            markers=True,
            category_orders={
                "month_name": [
                    "jan","feb","mar","apr","may","jun",
                    "jul","aug","sep","oct","nov","dec"
                ]
            },
            title="Arrival - Departure Passenger Difference"
        )
        fig.add_hline(
        y=0,
        line_dash="dash",
        line_color="red",
        line_width=2
        )
        fig.update_layout(
            autosize=True,
            xaxis_title="Month",
            yaxis_title="Passengers (Arrival - Departure)",
            template="plotly_white"
        )

        return fig

    # ========================================================================

    @render_plotly
    def plot_weekly_traffic():
        df_weekly = (
        df_avinor
        .filter(
            ((pl.col("departure_airport_iata") == airport()) |
            (pl.col("arrival_airport_iata") == airport())) &
            (pl.col("date_time_of_departure").dt.date().is_between(
                LAST_MONTH_AVINOR,
                END_DATE_AVINOR
            ))
        )
        .with_columns(
            pl.col("date_time_of_departure").dt.date().alias("date")
        )
        .group_by("date")
        .agg(
            pl.count().alias("daily_flights")
        )
        .with_columns(
            pl.col("date").dt.strftime("%A").alias("weekday_name"),
            pl.col("date").dt.weekday().alias("weekday")
        )
        .group_by(["weekday_name", "weekday"])
        .agg(
            pl.col("daily_flights").mean().round(0).alias("avg_flights")
        )
        .sort("weekday"))

        # df_weekly.write_csv("weekly.txt")
    
   
        pdf = df_weekly.to_pandas()


        fig = px.bar(
            pdf,
            x="weekday_name",
            y="avg_flights",
            title=f"Average Flights per Weekday for {LAST_MONTH_AVINOR.strftime('%B %Y')}",
            labels={
                "weekday_name": "Day of Week",
                "avg_flights": "Average Flights"
            }
        )
        fig.update_layout(
            xaxis_title="Week day",
            yaxis_title="Flights",
            legend_title="Type",
            paper_bgcolor="white",
            autosize=True,
            template="plotly_white"
        )

        return fig


    # ========================================================================

    @render_plotly
    def plot_hourly_traffic():
        df_hourly = (
            df_avinor
            .filter(
               ( (pl.col("departure_airport_iata") == airport()) |
                (pl.col("arrival_airport_iata") == airport()) ) &
                (pl.col("date_time_of_departure").dt.date().is_between(
                    LAST_MONTH_AVINOR,
                    END_DATE_AVINOR
                ))
            )
            .with_columns([
                pl.col("date_time_of_departure").dt.date().alias("date"),
                pl.col("date_time_of_departure").dt.hour().alias("hour")
            ])
        
            .group_by(["date", "hour"])
            .agg(
                pl.count().alias("hourly_flights")
            )
        
            .group_by("hour")
            .agg(
                pl.col("hourly_flights").mean().alias("avg_flights")
            )
            .sort("hour")
        )

        pdf = df_hourly.to_pandas()

        fig = px.line(
            pdf,
            x="hour",
            y="avg_flights",
            markers=True,
            title=f"Average Flights per Hour of Day for {LAST_MONTH_AVINOR.strftime('%B %Y')}",
            labels={
                "hour": "Hour of Day",
                "avg_flights": "Average Flights"
            }
        )
        fig.update_layout(
            autosize=True,
            xaxis_title="Hour of Day",
            yaxis_title="Flights",
            legend_title="Type",
            template="plotly_white",
            paper_bgcolor="white"
        )
        return fig

    # ========================================================================

    @render_widget
    def plot_flights_ipyleaflet():

        routes = (
        df_avinor_kepler
        .filter(pl.col("dep_iata") == airport())
        .filter(
            pl.col("dep_date").is_between(LAST_MONTH_AVINOR, END_DATE_AVINOR)
        )
        .group_by("arr_iata")
        .agg(
            pl.len().alias("flight_count"),
            pl.first("arr_lat"),
            pl.first("arr_lon")
        )
        )
        dep = (
        df_avinor_kepler
        .filter(pl.col("dep_iata") == airport())
        .select(["dep_lat", "dep_lon"])
        .drop_nulls()
        .head(1)
        .to_pandas()
        )
        dep_lat, dep_lon = dep.iloc[0]

        m = Map(center=(dep_lat, dep_lon), zoom=4)

        # m.add(Marker(location=( df["latitude_deg"][0], df["longitude_deg"][0] )))
        df = routes.to_pandas()
        df["flight_class"] = pd.qcut(
            df["flight_count"],
            q=5,
            labels=False,
            duplicates="drop"
        )

        df["flight_class"] = df["flight_class"].fillna(0).astype(int)

        opacity_map = {
            0: 0.3,
            1: 0.45,
            2: 0.55,
            3: 0.7,
            4: 1.0
        }

        weight_map = {
            0: 1,
            1: 1,
            2: 2,
            3: 2,
            4: 2
        }

        for _, row in df.iterrows():

            if pd.isna(row["arr_lat"]) or pd.isna(row["arr_lon"]):
                continue

            line = Polyline(
                locations=[
                    (dep_lat, dep_lon),
                    (row["arr_lat"], row["arr_lon"])
                ],
                color="blue",
                weight=weight_map[row["flight_class"]],
                opacity=opacity_map[row["flight_class"]],
                lineCap='round'
            )

            m.add(line)

        m.add(CircleMarker(
            location=(dep_lat, dep_lon),
            radius=6,
            color="red"
        ))

        return m

